{"command":"$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2025-09-03'; 'Content-Type' = 'application/json' }
$body = @{ query = 'Atlas OS' } | ConvertTo-Json -Compress
$search = Invoke-RestMethod -Method Post -Uri 'https://api.notion.com/v1/search' -Headers $headers -Body $body
$page = $search.results | Where-Object { $_.object -eq 'page' -and ($_.properties.title.title.plain_text -join '') -eq 'Atlas OS' } | Select-Object -First 1
if (-not $page) { throw 'Atlas OS page not found' }
$page.id
$children = Invoke-RestMethod -Method Get -Uri ("https://api.notion.com/v1/blocks/{0}/children?page_size=100" -f $page.id) -Headers $headers
$children.results | Select-Object id,type,has_children | ConvertTo-Json -Depth 5","workdir":"C:\Users\Gustavo\.openclaw\workspace","yieldMs":10000,"timeout":40}

