$code = @'
import os, json, requests
TOKEN=os.environ['NOTION_TOKEN']
HEAD={'Authorization':f'Bearer {TOKEN}','Notion-Version':'2025-09-03'}

def get(url):
    r=requests.get(url,headers=HEAD); r.raise_for_status(); return r.json()

def post(url,payload):
    r=requests.post(url,headers={**HEAD,'Content-Type':'application/json'},json=payload); r.raise_for_status(); return r.json()

search=post('https://api.notion.com/v1/search',{'query':'Atlas OS'})
page=next(x for x in search['results'] if x['object']=='page' and ''.join(t['plain_text'] for t in x['properties']['title']['title'])=='Atlas OS')
pid=page['id']
children=get(f'https://api.notion.com/v1/blocks/{pid}/children?page_size=100')['results']

def rt(arr):
    return ''.join(x.get('plain_text','') for x in arr)

for i,b in enumerate(children,1):
    t=b['type']
    txt=''
    if t in ('paragraph','heading_1','heading_2','heading_3','toggle','callout','bulleted_list_item','numbered_list_item','to_do'):
        data=b[t]
        key='rich_text' if 'rich_text' in data else None
        if key: txt=rt(data[key])
        if t=='to_do': txt = ('[x] ' if data.get('checked') else '[ ] ') + txt
    elif t=='child_page': txt=b[t]['title']
    elif t=='table': txt=f"table width={b[t]['table_width']}"
    print(f'{i:02d}. {t}: {txt}')
    if t=='table':
        rows=get(f"https://api.notion.com/v1/blocks/{b['id']}/children?page_size=100")['results']
        for r in rows[:10]:
            cells=[''.join(x.get('plain_text','') for x in cell) for cell in r['table_row']['cells']]
            print('    ROW:', ' | '.join(cells))
        if len(rows)>10: print(f'    ... {len(rows)} rows')
'@; $tmp=Join-Path $env:TEMP 'atlas_dump.py'; Set-Content -Path $tmp -Value $code; python $tmp

